import urllib.request
import csv
import io

# Try to download OWID rice production data
url = "https://ourworldindata.org/grapher/rice-production.csv"
headers = {"User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36"}
req = urllib.request.Request(url, headers=headers)
response = urllib.request.urlopen(req, timeout=15)
data = response.read().decode("utf-8", errors="ignore")

# Parse CSV
reader = csv.reader(io.StringIO(data))
rows = list(reader)

# Get header
print("Header:", rows[0])

# Find 2023 data for major rice producers
countries = ["China", "India", "Bangladesh", "Indonesia", "Vietnam", "Thailand"]
for row in rows:
    if len(row) >= 3:
        try:
            year = int(row[2])
            if year == 2023 and row[1] in countries:
                print(row)
        except:
            pass

# Also show all 2023 data sorted by production
prod_2023 = []
for row in rows[1:]:
    if len(row) >= 4:
        try:
            year = int(row[2])
            if year == 2023:
                prod = float(row[3])
                prod_2023.append((row[1], prod))
        except:
            pass

prod_2023.sort(key=lambda x: -x[1])
print("\nTop 10 rice producers in 2023:")
for i, (country, prod) in enumerate(prod_2023[:10]):
    print(f"{i+1}. {country}: {prod:,.0f}")
